#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10,INF=5e8;

struct Node{
    int a00,a01,a10,a11;
    inline Node operator*(Node x){
        Node res;
        res.a00=max(a00+x.a00,a01+x.a10);
        res.a01=max(a00+x.a01,a01+x.a11);
        res.a10=max(a10+x.a00,a11+x.a10);
        res.a11=max(a10+x.a01,a11+x.a11);
        return res;
    }
}v[N];

int n,m,a[N],sz[N],son[N],top[N],dfn[N],w[N],num,fa[N],s[N][2],g[N][2],f[N][2],en[N],rt[N];
vector<int> e[N];

void dfs1(int x,int lst){
    fa[x]=lst,sz[x]=1;
    for(int y:e[x])
        if(y!=lst){
            dfs1(y,x);
            sz[x]+=sz[y];
            if(sz[y]>sz[son[x]])
                son[x]=y;
        }
}

void pushup(int x){
    v[x]=v[s[x][1]]*((Node){g[x][0],g[x][1],g[x][0],-INF})*v[s[x][0]];
}

int build(int l,int r,int f,int root){
    if(l>r) return 0;
    int mid=l+r>>1,u=w[mid];
    s[u][0]=build(l,mid-1,u,root);
    s[u][1]=build(mid+1,r,u,root);
    fa[u]=f,rt[u]=root;
    pushup(u);
    return u;
}

void dfs2(int x,int topx){
    top[x]=topx;
    en[x]=x;
    dfn[x]=++num;
    w[num]=x;
    if(son[x]){
        dfs2(son[x],topx);
        en[x]=en[son[x]];
    }
    g[x][0]=0;
    g[x][1]=a[x];
    for(int y:e[x])
        if(y!=fa[x] && y!=son[x]){
            dfs2(y,y);
            g[x][0]+=max(f[y][0],f[y][1]);
            g[x][1]+=f[y][0];
        }
    if(son[x]){
        f[x][0]=g[x][0]+max(f[son[x]][0],f[son[x]][1]);
        f[x][1]=g[x][1]+f[son[x]][0];
    }else{
        f[x][0]=g[x][0];
        f[x][1]=g[x][1];
    }
    if(x==topx)
        build(dfn[x],dfn[en[x]],fa[x],w[dfn[x]+dfn[en[x]]>>1]);
}

void modify(int x){
    pushup(x);
    while(x!=rt[x]){
        x=fa[x];
        pushup(x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<n;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        e[u].push_back(v);
        e[v].push_back(u);
    }
    v[0]={0,-INF,-INF,0};
    dfs1(1,0);
    dfs2(1,1);
    // for(int i=1;i<=n;i++)
        // printf("%d %d\n",g[i][0],g[i][1]);
    // Node tmp=query(1,1,n,dfn[1],dfn[en[1]]);
    // printf("%d\n",max({tmp.a00,tmp.a01,tmp.a10,tmp.a11}));
    int la=0;
    while(m--){
        int x,y;
        scanf("%d%d",&x,&y);
        x^=la;
        for(int u=x;u;u=fa[u]){
            u=rt[u];
            if(!fa[u])
                break;
            Node tmp=v[u];
            int v0=max(tmp.a00,tmp.a10),v1=max(tmp.a01,tmp.a11);
            g[fa[u]][0]-=max(v0,v1);
            g[fa[u]][1]-=v0;
        }
        g[x][1]+=y-a[x];
        a[x]=y;
        modify(x);
       for(int u=x;u;u=fa[u]){
            u=rt[u];
            if(!fa[u])
                break;
            Node tmp=v[u];
            int v0=max(tmp.a00,tmp.a10),v1=max(tmp.a01,tmp.a11);
            g[fa[u]][0]+=max(v0,v1);
            g[fa[u]][1]+=v0;
            modify(fa[u]);
        }
        Node tmp=v[rt[1]];
        printf("%d\n",la=max({tmp.a00,tmp.a01,tmp.a10,tmp.a11}));
    }
    return 0;
}
